import torch.nn as nn

class IntermediateDistillationLoss(nn.Module):
    def __init__(self, student_dim: int, teacher_dim: int, num_student_layers: int, num_teacher_layers: int):
        super().__init__()
        self.projections = nn.ModuleList([
            nn.Linear(student_dim, teacher_dim, bias=False)
            for _ in range(num_student_layers)
        ])
        self.num_teacher_layers = num_teacher_layers
        self.num_student_layers = num_student_layers

    def teacher_layer_for(self, student_idx: int) -> int:
        return int(student_idx * self.num_teacher_layers / self.num_student_layers)

    def forward(self, student_hidden_states, teacher_hidden_states):
        """
        student_hidden_states: list of (B, L, student_dim) tensors, one per student layer
        teacher_hidden_states: list of (B, L, teacher_dim) tensors, one per teacher layer
        """
        total_loss = 0.0
        for i, (s_h, proj) in enumerate(zip(student_hidden_states, self.projections)):
            t_idx = self.teacher_layer_for(i)
            t_h = teacher_hidden_states[t_idx]
            projected = proj(s_h)                          # (B, L, teacher_dim)
            # Cosine distance loss — more stable than MSE for high-dim vectors
            cos_sim = nn.functional.cosine_similarity(projected, t_h, dim=-1)  # (B, L)
            total_loss += (1 - cos_sim).mean()
        return total_loss / len(self.projections)
